import type { Tool } from "../../core/tools.js";
import { readdir } from "fs/promises";
import { join } from "path";

export const fileTree: Tool = {
  def: {
    name: "file_tree",
    description:
      "프로젝트 구조를 계층적으로 보여주는 명령어. 특정 디렉토리나 파일을 지정할 수 있다.",
    input_schema: {
      type: "object",
      properties: {
        path: { type: "string", description: "탐색할 경로 (선택). 기본값은 프로젝트 루트." },
        depth: { type: "number", description: "표시할 깊이 (0=루트, 1=직하 1 단계 등)" },
      },
      required: [],
    },
  },
  handler: async (input) => {
    const rootPath = process.env.AGENT_ROOT ?? ".";
    const targetPath = join(rootPath, input.path ?? "");
    const depth = input.depth ?? 3;

    let entries = await readdir(targetPath, { withFileTypes: true });
    const result: string[] = [];

    for (const entry of entries) {
      if (depth === 0) continue;
      const prefix = " ".repeat((depth - 1) * 2);
      const indent = entry.isDirectory() ? "|__" : "\u00bb";
      result.push(`${prefix}${indent} ${entry.name}`);

      if (entry.isDirectory() && depth > 1) {
        try {
          const subEntries = await readdir(join(targetPath, entry.name), { withFileTypes: true });
          for (const sub of subEntries) {
            if (depth === 1) continue;
            const subPrefix = " ".repeat(depth * 2);
            const subIndent = sub.isDirectory() ? "|__" : "\u00bb";
            result.push(`${subPrefix}${subIndent} ${sub.name}`);
          }
        } catch {}
      }
    }

    return result.join("\n");
  },
};
